        sed -i 's/GRUB_CMDLINE_LINUX="/GRUB_CMDLINE_LINUX="fips=1 /' /etc/default/grub
        update-grub
    fi
}

# Main function
main() {
    install_dracut_fips
    enable_fips
    regenerate_initramfs
    configure_grub
}

